async function run(agent) {
  await agent.aiTap("进入 Menu");
  await agent.aiTap("点击 Settings");
  await agent.aiTap("点击 Visualization");
  await agent.aiTap("启用 Show OK Code Field");
  await agent.aiTap("保存 Visualization 设置");
  await agent.aiInput("OK Code / 左上角命令", { value: "CJ20N" });
  await agent.aiTap("进入 Project Builder");
  await agent.aiKeyboardPress("Enter");
  await agent.aiTap("点击 Project Builder 工具栏上的 Open Project 图标");
  await agent.aiInput("Open Project 弹窗的 WBS element", { value: "EH-000000254-01" });
  await agent.aiTap("从 listbox shell 中选择匹配的 WBS/project 条目");
  await agent.aiTap("在 Project Builder Subproject EH-000000254 页面中打开 Edit 菜单");
  await agent.aiTap("选择创建资产/Create Asset 的菜单项或应用字段");
  await agent.aiInput("Create Asset 页面", { value: "必填资产字段（资产类别、描述、公司代码等" });
  await agent.aiTap("按当前 WBS 默认值补齐）");
  await agent.aiTap("在弹出的 listbox shell 中选择正确的资产类别/字段值");
  await agent.aiTap("点击 Additional data 图标/页签");
  await agent.aiTap("切换到 Time-dependent 页签");
  await agent.aiAssert("点击返回/确认图标 sap_178 保存当前资产主数据页签");
  await agent.aiTap("在 Create Asset 页面点击 OK");
  await agent.aiTap("回到 Project Builder Subproject 页面后点击保存图标 sap_190");
  await agent.aiAssert("确认状态栏出现 project EH-000000254 being changed 或项目已保存/已更改提示");
  await agent.aiTap("关闭 Performance/提示窗口");
  await agent.aiTap("重新点击 Open Project 图标 sap_244");
  await agent.aiInput("WBS element", { value: "EH-000000254-01" });
  await agent.aiTap("打开项目");
  await agent.aiTap("在 Project Builder Subproject 页面打开 Goto 菜单");
  await agent.aiTap("选择 Maintain Settlement Rule");
  const result = await agent.aiQuery("string, 读取 Maintain Settlement Rule Distribution Rules 表格中的 settlement receiver");
  await agent.aiTap("点击 More");
  await agent.aiTap("打开 settlement receiver 对应的资产主数据");
  const result = await agent.aiQuery("string, 读取 Display Asset Master data 页面中的 Asset 字段值");
  const result = await agent.aiQuery("string, 保存为变量 assetId");
  await agent.aiAssert("切换到 Time-dependent、Assignments、Origin 页签逐项检查");
  await agent.aiAssert("确认 Origin 页签中的 WBS element 为 EH-000000254-01");
  await agent.aiTap("返回 SAP Easy Access 后");
  await agent.aiInput("OK Code", { value: "AS03" });
  await agent.aiTap("进入 Display Asset Initial Screen");
  await agent.aiKeyboardPress("Enter");
  const result = await agent.aiQuery("string, 在 Display Asset Initial Screen 输入前面创建/读取到的 assetId");
  await agent.aiAssert("确认资产主数据可打开");
  await agent.aiTap("WBS assignment / settlement rule 与 EH-000000254-01 匹配");
}
